5945 const SCEV *ScalarEvolution::createNodeFromSelectLikePHI(PHINode *PN) {
5946   auto IsReachable =
5947       [&](BasicBlock *BB) { return DT.isReachableFromEntry(BB); };
5948   if (PN->getNumIncomingValues() == 2 && all_of(PN->blocks(), IsReachable)) {
5949     // Try to match
5950     //
5951     //  br %cond, label %left, label %right
5952     // left:
5953     //  br label %merge
5954     // right:
5955     //  br label %merge
5956     // merge:
5957     //  V = phi [ %x, %left ], [ %y, %right ]
5958     //
5959     // as "select %cond, %x, %y"
5960 
5961     BasicBlock *IDom = DT[PN->getParent()]->getIDom()->getBlock();
5962     assert(IDom && "At least the entry block should dominate PN");
5963 
5964     auto *BI = dyn_cast<BranchInst>(IDom->getTerminator());
5965     Value *Cond = nullptr, *LHS = nullptr, *RHS = nullptr;
5966 
5967     if (BI && BI->isConditional() &&
5968         BrPHIToSelect(DT, BI, PN, Cond, LHS, RHS) &&
5969         properlyDominates(getSCEV(LHS), PN->getParent()) &&
5970         properlyDominates(getSCEV(RHS), PN->getParent()))
5971       return createNodeForSelectOrPHI(PN, Cond, LHS, RHS);
5972   }
5973 
5974   return nullptr;
5975 }
