5977 const SCEV *ScalarEvolution::createNodeForPHI(PHINode *PN) {
5978   if (const SCEV *S = createAddRecFromPHI(PN))
5979     return S;
5980 
5981   if (Value *V = simplifyInstruction(PN, {getDataLayout(), &TLI, &DT, &AC}))
5982     return getSCEV(V);
